package com.ayush.springtest; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest; import java.util.*; import static org.junit.jupiter.api.Assertions.*; @DataJpaTest class UserRepositoryTest { @Autowired UserRepository repo; @Test void customFindByName(){ repo.save(new User(null,"Ayush")); List<User> users=repo.findByName("Ayush"); assertFalse(users.isEmpty()); }}